// EDTMRS - RiskBadge Component
import React from 'react';

const RISK_CONFIG = {
  safe:     { label: 'SAFE',     bg: 'bg-emerald-500/20', text: 'text-emerald-400', border: 'border-emerald-500/40', dot: 'bg-emerald-400' },
  medium:   { label: 'MEDIUM',   bg: 'bg-yellow-500/20',  text: 'text-yellow-400',  border: 'border-yellow-500/40',  dot: 'bg-yellow-400' },
  high:     { label: 'HIGH',     bg: 'bg-orange-500/20',  text: 'text-orange-400',  border: 'border-orange-500/40',  dot: 'bg-orange-400' },
  critical: { label: 'CRITICAL', bg: 'bg-red-500/20',     text: 'text-red-400',     border: 'border-red-500/40',     dot: 'bg-red-400'    },
  unknown:  { label: 'UNKNOWN',  bg: 'bg-gray-500/20',    text: 'text-gray-400',    border: 'border-gray-500/40',    dot: 'bg-gray-400'   },
  whitelisted: { label: 'SAFE', bg: 'bg-emerald-500/20', text: 'text-emerald-400', border: 'border-emerald-500/40', dot: 'bg-emerald-400' },
  blocked:  { label: 'BLOCKED',  bg: 'bg-red-600/20',     text: 'text-red-300',     border: 'border-red-600/40',     dot: 'bg-red-300'    },
};

export default function RiskBadge({ level, pulse = false }) {
  const cfg = RISK_CONFIG[level?.toLowerCase()] || RISK_CONFIG.unknown;
  return (
    <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold border ${cfg.bg} ${cfg.text} ${cfg.border}`}>
      <span className={`w-1.5 h-1.5 rounded-full ${cfg.dot} ${pulse && level !== 'safe' ? 'animate-pulse' : ''}`} />
      {cfg.label}
    </span>
  );
}
